namespace sv_597c01157fb54301a20715f595fa9025.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _recipes = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, cheese, and pancetta.", 30),
            new(2, "Margherita Pizza", "Simple pizza with tomato, mozzarella, and basil.", 45),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts and vegetables.", 25),
            new(5, "Mapo Tofu", "Silken tofu in a fiery Sichuan pepper sauce.", 20),
            new(6, "Dim Sum Dumplings", "Steamed pork and shrimp dumplings.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple and cilantro.", 35),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and tomato.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken and green salsa.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_recipes.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_597c01157fb54301a20715f595fa9025.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<h3>Recipes</h3>

<div>
    <label>Sort by:</label>
    <select value="@Sort" @onchange="OnSortChanged">
        <option value="newest">Newest</option>
        <option value="popular">Popular</option>
    </select>
</div>

@if (_error is not null)
{
    <div class="alert alert-danger mt-3">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <div class="mt-3">
        <p><em>Loading recipes...</em></p>
    </div>
}
else
{
    @if (_isRefreshing)
    {
        <div class="mt-2">
            <small><em>Refreshing…</em></small>
        </div>
    }

    <ul class="list-group mt-3">
        @foreach (var recipe in GetSortedRecipes())
        {
            <li class="list-group-item">
                <strong>@recipe.Title</strong> — @recipe.PrepTimeMinutes min
                <br />
                <span>@recipe.Description</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, token);

            if (token.IsCancellationRequested)
                return;

            _recipes = result;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // We cancelled this ourselves (new cuisine selected or disposal). Do nothing.
        }
        catch (OperationCanceledException)
        {
            // External cancellation or timeout — not initiated by us.
            Logger.LogWarning("Recipe loading for cuisine {CuisineId} timed out or was cancelled externally.", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogWarning(ex, "Timeout loading recipes for cuisine {CuisineId}.", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}.", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private List<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return new();

        return Sort?.ToLowerInvariant() switch
        {
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes).ToList(),
            _ => _recipes.OrderByDescending(r => r.Id).ToList(),
        };
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        var newSort = e.Value?.ToString() ?? "newest";
        Navigation.NavigateTo($"/recipes/{CuisineId}?sort={newSort}");
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        if (_cts is not null)
        {
            _cts.Cancel();
            _cts.Dispose();
            _cts = null;
        }
    }
}

